import { type ReactNode, forwardRef } from "react";
import {
  Button as AriaButton,
  type ButtonProps as AriaButtonProps,
} from "react-aria-components";
import { clsx } from "clsx";
import * as styles from "./ListItemAction.css";
import { _BaseIcon as Icon } from "../Icon/_BaseIcon";
import { _BaseLink, type BaseLinkProps } from "../Link/_BaseLink";

export interface ListItemActionBaseProps {
  /**
   * Icon to display on the right side of the list item.
   * Should be a FontAwesome SVG icon element (e.g., `<PlusIcon />`).
   */
  icon: ReactNode;

  /**
   * The text content of the list item.
   * This serves as the accessible name for the interactive element.
   */
  children: React.ReactNode;

  /**
   * Whether the list item is disabled.
   * @default false
   */
  disabled?: boolean;
}

export interface ListItemActionLinkProps
  extends
    Omit<BaseLinkProps, "isDisabled" | "children">,
    ListItemActionBaseProps {
  /**
   * Renders the component as a link.
   * When omitted or set to "link", the component renders as an anchor element.
   */
  as?: "link";
}

export interface ListItemActionButtonProps
  extends
    Omit<AriaButtonProps, "isDisabled" | "children">,
    ListItemActionBaseProps {
  /**
   * Renders the component as a button.
   * When using as="button", ensure the children provide a meaningful accessible name,
   * or provide an aria-label for screen reader users.
   */
  as: "button";
}

export type ListItemActionProps =
  | ListItemActionLinkProps
  | ListItemActionButtonProps;

const ListItemActionLink = forwardRef<
  HTMLAnchorElement,
  ListItemActionLinkProps
>(({ children, icon, disabled = false, className, as: _as, ...props }, ref) => {
  const listItemActionClassName = clsx(
    styles.listItemAction({ disabled }),
    className
  );

  return (
    <_BaseLink
      ref={ref}
      className={listItemActionClassName}
      isDisabled={disabled}
      {...props}
    >
      <span className={styles.listItemActionText}>{children}</span>
      <Icon size={16}>{icon}</Icon>
    </_BaseLink>
  );
});

ListItemActionLink.displayName = "ListItemActionLink";

const ListItemActionButton = forwardRef<
  HTMLButtonElement,
  ListItemActionButtonProps
>(({ children, icon, disabled = false, className, as: _as, ...props }, ref) => {
  const listItemActionClassName = clsx(
    styles.listItemAction({ disabled }),
    className
  );

  return (
    <AriaButton
      ref={ref}
      className={listItemActionClassName}
      isDisabled={disabled}
      {...props}
    >
      <span className={styles.listItemActionText}>{children}</span>
      <Icon size={16}>{icon}</Icon>
    </AriaButton>
  );
});

ListItemActionButton.displayName = "ListItemActionButton";

/**
 * ListItemAction - Interactive content wrapper for list items.
 *
 * Can be rendered as either a link (default) or a button using the `as` prop.
 *
 * The `children` prop serves as the accessible name for the interactive element.
 * When using as="button", ensure the text content is descriptive for screen reader users.
 */
export function ListItemAction(
  props: ListItemActionLinkProps
): React.ReactElement;
export function ListItemAction(
  props: ListItemActionButtonProps
): React.ReactElement;
export function ListItemAction(props: ListItemActionProps): React.ReactElement {
  if (props.as === "button") {
    return <ListItemActionButton {...props} />;
  }
  return <ListItemActionLink {...props} />;
}

ListItemAction.displayName = "ListItemAction";
